 '腾讯混元':['hunyuan-turbos-latest','hunyuan-pro'],'豆包（火山方舟）':['doubao-seed-1-6','doubao-1-5-pro-32k'],'文心千帆':['ernie-4.5-8k-preview','ernie-speed-128k'],'通义百炼':['qwen3-max','qwen-plus','qwen-turbo'],'智谱 AI':['glm-4.5','glm-4-flash'],'DeepSeek':['deepseek-v4-pro','deepseek-v4-flash','deepseek-chat','deepseek-reasoner'],Kimi:['kimi-k2-0711-preview','moonshot-v1-32k'],'小米 MiMo':['mimo-v2.5-pro'],'讯飞星火':['spark-x1','generalv3.5'],'MiniMax':['MiniMax-M2','MiniMax-Text-01'],'阶跃星辰':['step-2-16k','step-1-32k'],'零一万物':['yi-lightning','yi-large'],'商汤日日新':['SenseChat-5','SenseNova-V6'],'百川智能':['Baichuan4','Baichuan3-Turbo'],OpenAI:['gpt-5.4','gpt-5.4-mini','gpt-4.1'],Anthropic:['claude-opus-4-1','claude-sonnet-4'],'Google Gemini':['gemini-2.5-pro','gemini-2.5-flash'],'自定义 OpenAI 兼容':['自定义模型']
}
