 '腾讯混元':'https://console.cloud.tencent.com/hunyuan', '豆包（火山方舟）':'https://console.volcengine.com/ark', '文心千帆':'https://console.bce.baidu.com/qianfan', '通义百炼':'https://bailian.console.aliyun.com/', '智谱 AI':'https://open.bigmodel.cn/', DeepSeek:'https://platform.deepseek.com/', Kimi:'https://platform.moonshot.cn/', '小米 MiMo':'https://mimo.mi.com/', '讯飞星火':'https://console.xfyun.cn/', MiniMax:'https://platform.minimaxi.com/', '阶跃星辰':'https://platform.stepfun.com/', '零一万物':'https://platform.lingyiwanwu.com/', '商汤日日新':'https://console.sensenova.cn/', '百川智能':'https://platform.baichuan-ai.com/', OpenAI:'https://platform.openai.com/', Anthropic:'https://console.anthropic.com/', 'Google Gemini':'https://aistudio.google.com/', '自定义 OpenAI 兼容':'https://platform.openai.com/docs/api-reference'
}
const providerApiBases:Record<string,string>={'腾讯混元':'https://api.hunyuan.cloud.tencent.com/v1','豆包（火山方舟）':'https://ark.cn-beijing.volces.com/api/v3','文心千帆':'https://qianfan.baidubce.com/v2','通义百炼':'https://dashscope.aliyuncs.com/compatible-mode/v1','智谱 AI':'https://open.bigmodel.cn/api/paas/v4',DeepSeek:'https://api.deepseek.com',Kimi:'https://api.moonshot.cn/v1','小米 MiMo':'https://api.xiaomimimo.com/v1','讯飞星火':'https://spark-api-open.xf-yun.com/v1',MiniMax:'https://api.minimax.chat/v1','阶跃星辰':'https://api.stepfun.com/v1','零一万物':'https://api.lingyiwanwu.com/v1','商汤日日新':'https://api.sensenova.cn/compatible-mode/v1','百川智能':'https://api.baichuan-ai.com/v1',OpenAI:'https://api.openai.com',Anthropic:'https://api.anthropic.com','Google Gemini':'https://generativelanguage.googleapis.com','自定义 OpenAI 兼容':''}
let timer:number
let unlistenFloating:(()=>void)|undefined
let unlistenSelection:(()=>void)|undefined
let unlistenFloatingConfig:(()=>void)|undefined
let unlistenFloatingResize:(()=>void)|undefined
let unlistenUsageUpdated:(()=>void)|undefined
let unlistenProxyState:(()=>void)|undefined
onMounted(()=>{
 void getVersion().then(version=>{appVersion.value=version})
 void listen<boolean>('floating-state',event=>{
   floatingEnabled.value=event.payload
   localStorage.setItem('token-manager-floating',event.payload?'1':'0')
 }).then(unlisten=>{unlistenFloating=unlisten})
 void listen<string>('dashboard-selection',event=>{selectedDashboard.value=event.payload}).then(unlisten=>{unlistenSelection=unlisten})
 void listen<FloatingConfig>('floating-config',event=>{const value={...event.payload,layout:event.payload.layout==='list'?'list':'grid'} as FloatingConfig;floatingConfig.value=value;floatingCollapsed.value=value.miniMode;localStorage.setItem('token-manager-floating-config',JSON.stringify(value));if(floatingMode)void applyFloatingModeSize()}).then(unlisten=>{unlistenFloatingConfig=unlisten})
 void listen<string>('usage-updated',()=>{if(!isSyncing.value)void syncCurrentView()}).then(unlisten=>{unlistenUsageUpdated=unlisten})
 void listen<ProxyEndpoint[]>('proxy-state',event=>{proxyEndpoints.value=event.payload;allProxyStatus.value=`实时监控已开启：${event.payload.length} 个账户`}).then(unlisten=>{unlistenProxyState=unlisten})
 timer=window.setInterval(()=>{
   now.value=Date.now()
   if (!isSyncing.value && now.value-lastRefreshed.value >= refreshIntervalMs) void syncCurrentView()
 },1000)
 void syncCurrentView()
 if(floatingMode) void initializeFloatingWindow()
 if(!floatingMode&&floatingEnabled.value) void invoke('set_floating_window',{enabled:true})
})
onUnmounted(()=>{clearInterval(timer);unlistenFloating?.();unlistenSelection?.();unlistenFloatingConfig?.();unlistenFloatingResize?.();unlistenUsageUpdated?.();unlistenProxyState?.()})
const resetText=computed(()=>{const seconds=Math.max(0,Math.floor((new Date(dashboard.value.resetAt).getTime()-now.value)/1000)); return `${Math.floor(seconds/60)}分${String(seconds%60).padStart(2,'0')}秒`})
const totalCost=computed(()=>usage.value.reduce((s,x)=>s+x.cost,0))
const selectedDashboardDef=computed(()=>modelDashboards.value.find(item=>item.key===selectedDashboard.value))
const dashboardUsage=computed(()=>selectedDashboard.value==='__all__'?usage.value:selectedDashboard.value==='__codex__'?[]:usage.value.filter(item=>item.model===selectedDashboardDef.value?.model&&item.provider===selectedDashboardDef.value?.provider))
const dashboardTitle=computed(()=>selectedDashboard.value==='__all__'?'全部模型':selectedDashboard.value==='__codex__'?'Codex 专属':selectedDashboardDef.value?.label||'模型仪表盘')
const dashboardAdvice=computed(()=>selectedDashboard.value==='__codex__'
 ? ['数据来自 Codex 本地状态库和日志，不需要 API Key。','5 小时和 7 天数字是基于本地可验证日志与个人预算计算，不冒充 OpenAI 官方服务端余额。']
 : selectedDashboard.value==='__all__'
 ? ['这里汇总所有已接入模型，可通过上方仪表盘标签查看单个模型。','独立模型视图中的数字、图表、调用记录和提示均不会混入其他模型。']
 : dashboardUsage.value.length
   ? [`${selectedDashboardDef.value?.model} 今日已记录 ${dashboardToday.value.length} 次调用，成本 ¥${dashboardCost.value.toFixed(2)}。`,`该页仅分析 ${selectedDashboardDef.value?.provider} / ${selectedDashboardDef.value?.model} 的本地真实记录。`]
   : [`${selectedDashboardDef.value?.model} 暂无真实调用记录。`,`通过已配置账户同步或本地代理产生调用后，此处将只显示该模型数据。`])
const dashboardToday=computed(()=>dashboardUsage.value.filter(x=>new Date(x.at).toDateString()===new Date().toDateString()))
const dashboardInput=computed(()=>dashboardToday.value.reduce((sum,x)=>sum+x.input,0))
const dashboardOutput=computed(()=>dashboardToday.value.reduce((sum,x)=>sum+x.output,0))
const dashboardCached=computed(()=>dashboardToday.value.reduce((sum,x)=>sum+x.cached,0))
const dashboardCost=computed(()=>dashboardToday.value.reduce((sum,x)=>sum+x.cost,0))
const dashboardFailedCalls=computed(()=>dashboardToday.value.filter(x=>x.task==='失败').length)
const dashboardCacheRate=computed(()=>dashboardInput.value?Math.round(dashboardCached.value/dashboardInput.value*100):0)
const dashboardWeekTotal=computed(()=>dashboardUsage.value.filter(item=>new Date(item.at).getTime()>=now.value-7*86_400_000).reduce((sum,item)=>sum+item.input+item.output,0))
/** 每个平台使用稳定的数据色；Logo 仍保持用户指定的黑白显示。 */
const providerColors:Record<string,string>={
 'Codex':'#1d1d1f','OpenAI':'#10a37f','Anthropic':'#d97757','Google Gemini':'#4285f4',
 'DeepSeek':'#4d6bfe','腾讯混元':'#00a870','豆包（火山方舟）':'#2e90fa','文心千帆':'#2563eb',
 '通义百炼':'#6c5ce7','智谱 AI':'#245bdb','Kimi':'#7b61ff','小米 MiMo':'#ff6900',
 '讯飞星火':'#f59e0b','MiniMax':'#e5484d','阶跃星辰':'#0ea5e9','零一万物':'#1f9d74',
 '商汤日日新':'#df3b3b','百川智能':'#8b5cf6','自定义 OpenAI 兼容':'#52525b'
}
const fallbackChartColors=['#0f766e','#c2410c','#0369a1','#7e22ce','#be123c','#3f6212','#4338ca','#a16207']
function providerColor(provider:string){if(providerColors[provider])return providerColors[provider];let hash=0;for(const char of provider)hash=(hash*31+char.charCodeAt(0))>>>0;return fallbackChartColors[hash%fallbackChartColors.length]}
const providerBreakdown=computed(()=>{const totals=new Map<string,{tokens:number;calls:number;cost:number}>();for(const item of usage.value){const row=totals.get(item.provider)||{tokens:0,calls:0,cost:0};row.tokens+=item.input+item.output;row.calls++;row.cost+=item.cost;totals.set(item.provider,row)}const rows=[...totals.entries()].map(([provider,value])=>({provider,...value})).sort((a,b)=>b.tokens-a.tokens);const max=Math.max(1,...rows.map(row=>row.tokens));return rows.map(row=>({...row,percent:Math.max(3,row.tokens/max*100)}))})
const monthlyProviderCosts=computed(()=>providerBreakdown.value.filter(item=>item.cost>0).sort((a,b)=>b.cost-a.cost))
const monthlyCostTotal=computed(()=>monthlyProviderCosts.value.reduce((sum,item)=>sum+item.cost,0))
const monthlyCostGradient=computed(()=>{let cursor=0;const stops=monthlyProviderCosts.value.map(item=>{const next=cursor+(monthlyCostTotal.value?item.cost/monthlyCostTotal.value*100:0);const stop=`${providerColor(item.provider)} ${cursor}% ${next}%`;cursor=next;return stop});return stops.length?`conic-gradient(${stops.join(',')})`:'#f2f2f7'})
const monthlyCostTrend=computed(()=>{const daily=Array.from({length:30},(_,i)=>{const date=new Date(now.value-(29-i)*86_400_000);return{key:localDayKey(date),cost:0}});for(const item of usage.value){const row=daily.find(day=>day.key===localDayKey(new Date(item.at)));if(row)row.cost+=item.cost}const max=Math.max(.01,...daily.map(day=>day.cost));return daily.map((day,index)=>`${index/(daily.length-1)*600},${135-day.cost/max*110}`).join(' ')})
const balanceStatusText=computed(()=>isDeepSeekDashboard.value?(dashboardBalance.value?`官方余额 · ${dashboardBalance.value.currency}`:balanceError.value||'等待官方余额接口同步'):selectedDashboardDef.value?.provider==='OpenAI'||selectedDashboardDef.value?.provider==='Anthropic'?'模型 API Key 不含组织账单权限':selectedDashboardDef.value?.provider==='Google Gemini'?'需单独配置 Google Cloud Billing IAM':selectedDashboardDef.value?.provider==='自定义 OpenAI 兼容'?'由中转服务决定，当前使用代理统计':'需厂商云账户签名或账单导入')
const codexTodayTokens=computed(()=>codexSeries.value.filter(item=>localDayKey(new Date(item.at*1000))===localDayKey(new Date(now.value))).reduce((sum,item)=>sum+item.tokens,0))
const activeModelCount=computed(()=>new Set(usage.value.filter(item=>localDayKey(new Date(item.at))===localDayKey(new Date(now.value))).map(item=>`${item.provider}::${item.model}`)).size+(codexTodayTokens.value?1:0))
const todayUsedProviders=computed(()=>{const rows=new Map<string,{provider:string,tokens:number,calls:number}>();for(const item of usage.value.filter(item=>localDayKey(new Date(item.at))===localDayKey(new Date(now.value)))){const row=rows.get(item.provider)||{provider:item.provider,tokens:0,calls:0};row.tokens+=item.input+item.output;row.calls++;rows.set(item.provider,row)}if(codexTodayTokens.value)rows.set('Codex',{provider:'OpenAI',tokens:codexTodayTokens.value,calls:todayCodexTurns.value});return[...rows.values()].sort((a,b)=>b.tokens-a.tokens).slice(0,8)})
const dashboardAccount=computed(()=>savedAccounts.value.find(item=>item.id===selectedDashboardDef.value?.accountId))
const isDeepSeekDashboard=computed(()=>selectedDashboardDef.value?.provider==='DeepSeek')
const isApiDashboard=computed(()=>selectedDashboard.value!=='__all__'&&selectedDashboard.value!=='__codex__')
const dashboardBalance=computed(()=>accountBalances.value.find(item=>item.account_id===dashboardAccount.value?.id&&item.currency==='CNY'))
const balanceChange=computed(()=>deepseekBalanceHistory.value.length>1?deepseekBalanceHistory.value[deepseekBalanceHistory.value.length-1].total_balance-deepseekBalanceHistory.value[0].total_balance:0)
const deepseekBalancePoints=computed(()=>{const rows=deepseekBalanceHistory.value;if(!rows.length)return'';const min=Math.min(...rows.map(x=>x.total_balance));const max=Math.max(...rows.map(x=>x.total_balance));return rows.map((item,index)=>`${rows.length===1?300:index/(rows.length-1)*600},${140-(item.total_balance-min)/Math.max(.01,max-min)*115}`).join(' ')})
const dashboardLastUsage=computed(()=>dashboardUsage.value[0])
const availableModels=computed(()=>savedAccounts.value.flatMap(account=>(accountModels.value[account.id]?.length?accountModels.value[account.id]:providerModels[account.provider]||['自定义模型']).map(model=>({key:`${account.id}::${model}`,accountId:account.id,provider:account.provider,model,label:`${account.name} · ${model}`}))))
const refreshedText=computed(()=>new Intl.DateTimeFormat('zh-CN',{hour:'2-digit',minute:'2-digit',second:'2-digit'}).format(lastRefreshed.value))
const nextRefreshText=computed(()=>{
 const seconds=Math.max(0,Math.ceil((refreshIntervalMs-(now.value-lastRefreshed.value))/1000))
 return `下次自动刷新 ${seconds} 秒后`
})
const remaining5h=computed(()=>Math.max(0,100-Math.round(used5h.value/budget5h.value*100)))
const remaining7d=computed(()=>Math.max(0,100-Math.round(used7d.value/budget7d.value*100)))
const monthlyBudget=computed(()=>loadLocal('token-manager-monthly-budget',200))
const codexInsights=computed(()=>buildCodexInsights(codexSeries.value,used7d.value,budget7d.value,monthlyBudget.value))
const used5hPercent=computed(()=>Math.min(100,100-remaining5h.value))
const used7dPercent=computed(()=>Math.min(100,100-remaining7d.value))
function localDayKey(value:Date){return `${value.getFullYear()}-${String(value.getMonth()+1).padStart(2,'0')}-${String(value.getDate()).padStart(2,'0')}`}
function setTokenChartRange(range:TokenChartRange){tokenChartRange.value=range;localStorage.setItem('token-manager-token-chart-range',String(range))}
const allTokenChart=computed(()=>{
 const range=tokenChartRange.value
 const days=Array.from({length:range},(_,index)=>{const date=new Date(now.value);date.setHours(0,0,0,0);date.setDate(date.getDate()-(range-1-index));return{key:localDayKey(date),day:date.toLocaleDateString('zh-CN',{month:'2-digit',day:'2-digit'}),providers:new Map<string,number>(),total:0}})
 const byDay=new Map(days.map(day=>[day.key,day]))
 const add=(key:string,provider:string,tokens:number)=>{if(!tokens)return;const day=byDay.get(key);if(!day)return;day.providers.set(provider,(day.providers.get(provider)||0)+tokens);day.total+=tokens}
 for(const item of usage.value)add(localDayKey(new Date(item.at)),item.provider,item.input+item.output)
 for(const point of codexSeries.value)add(localDayKey(new Date(point.at*1000)),'Codex',point.tokens)
 const providerTotals=new Map<string,number>()
 for(const day of days)for(const [provider,tokens] of day.providers)providerTotals.set(provider,(providerTotals.get(provider)||0)+tokens)
 const order=[...providerTotals.entries()].sort((a,b)=>b[1]-a[1]).map(([provider])=>provider)
 const max=Math.max(1,...days.map(day=>day.total))
 const rows=days.map((day,index)=>({
  ...day,
  label:range===7||index===0||index===range-1||index%5===4?day.day:'',
  height:day.total?Math.max(2,day.total/max*100):0,
  segments:order.map(provider=>({provider,tokens:day.providers.get(provider)||0,color:providerColor(provider),height:(day.providers.get(provider)||0)/max*100})).filter(item=>item.tokens>0)
 }))
 return{rows,legend:order.map(provider=>({provider,tokens:providerTotals.get(provider)||0,color:providerColor(provider)})),total:rows.reduce((sum,row)=>sum+row.total,0),peak:rows.reduce((peak,row)=>row.total>peak.total?row:peak,rows[0]),activeProviders:order.length}
})
const tokenChartDailyAverage=computed(()=>Math.round(allTokenChart.value.total/tokenChartRange.value))
const chartBars=computed(()=>{
 const daily=new Map<string,{input:number;output:number;cached:number;codex:number;cost:number;calls:number}>()
 for(let i=6;i>=0;i--){const date=new Date(now.value);date.setDate(date.getDate()-i);daily.set(localDayKey(date),{input:0,output:0,cached:0,codex:0,cost:0,calls:0})}
 for(const item of dashboardUsage.value){const bucket=daily.get(localDayKey(new Date(item.at)));if(bucket){bucket.input+=item.input;bucket.output+=item.output;bucket.cached+=item.cached;bucket.cost+=item.cost;bucket.calls++}}
 if(selectedDashboard.value==='__all__'||selectedDashboard.value==='__codex__')for(const point of codexSeries.value){const bucket=daily.get(localDayKey(new Date(point.at*1000)));if(bucket)bucket.codex+=point.tokens}
 const values=[...daily.entries()].map(([day,value])=>({day,label:day.slice(5),...value,total:value.input+value.output+value.codex}))
 const max=Math.max(1,...values.map(item=>item.total));return values.map(item=>({...item,height:item.total?Math.max(6,item.total/max*100):2}))
})
const modelChartSeries=computed(()=>{let cumulative=0;const source=chartBars.value.map(item=>({...item,cumulative:cumulative+=item.input+item.output}));const costMax=Math.max(1,...source.map(item=>item.cost));const tokenMax=Math.max(1,...source.map(item=>item.cumulative));const callsMax=Math.max(1,...source.map(item=>item.calls));const cacheMax=Math.max(1,...source.map(item=>item.cached));return source.map(item=>({...item,costHeight:item.cost?Math.max(7,item.cost/costMax*100):2,tokenHeight:item.cumulative?Math.max(7,item.cumulative/tokenMax*100):2,callsHeight:item.calls?Math.max(7,item.calls/callsMax*100):2,cacheHeight:item.cached?Math.max(7,item.cached/cacheMax*100):2}))})
const floatingBars=computed(()=>{
 const hour=Math.floor(now.value/3_600_000)*3_600_000
 const buckets=Array.from({length:5},(_,index)=>{const at=hour-(4-index)*3_600_000;return{at,label:new Date(at).toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit'}),tokens:0}})
 if(selectedDashboard.value==='__all__'||selectedDashboard.value==='__codex__'){for(const point of codexSeries.value){const pointHour=Math.floor(point.at*1000/3_600_000)*3_600_000;const bucket=buckets.find(item=>item.at===pointHour);if(bucket)bucket.tokens+=point.tokens}}
 else{for(const item of dashboardUsage.value){const pointHour=Math.floor(new Date(item.at).getTime()/3_600_000)*3_600_000;const bucket=buckets.find(value=>value.at===pointHour);if(bucket)bucket.tokens+=item.input+item.output}}
 const max=Math.max(1,...buckets.map(item=>item.tokens));return buckets.map(item=>({...item,height:item.tokens?Math.max(8,item.tokens/max*100):3}))
})
const balanceLevel=computed(()=>{const remaining=Math.min(remaining5h.value,remaining7d.value);return remaining<=10?'critical':remaining<=20?'warning':'normal'})
const balanceNotice=computed(()=>codexTokens.value===null?'尚未读取 Codex 日志':balanceLevel.value==='critical'?'余额低于 10%，请尽快切换任务':balanceLevel.value==='warning'?'余额低于 20%，请控制高消耗任务':'余额充足，监控正常')
const floatingModelNotice=computed(()=>selectedDashboard.value==='__all__'||selectedDashboard.value==='__codex__'?balanceNotice.value:isDeepSeekDashboard.value&&dashboardBalance.value?`DeepSeek 官方余额 ¥${dashboardBalance.value.total_balance.toFixed(2)} · ${dashboardBalance.value.is_available?'可正常调用':'余额不可用'}`:dashboardUsage.value.length?`已记录 ${dashboardUsage.value.length} 次 ${selectedDashboardDef.value?.model} 调用`:`${selectedDashboardDef.value?.model} 暂无调用数据`)
const currentTimeText=computed(()=>new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).format(now.value))
const globalRemaining=computed(()=>Math.min(remaining5h.value,remaining7d.value))
const todayTotalTokens=computed(()=>codexTodayTokens.value+usage.value.filter(item=>localDayKey(new Date(item.at))===localDayKey(new Date(now.value))).reduce((sum,item)=>sum+item.input+item.output,0))
const weekCost=computed(()=>{const since=now.value-7*86_400_000;return usage.value.filter(item=>new Date(item.at).getTime()>=since).reduce((sum,item)=>sum+item.cost,0)})
const todayCodexTurns=computed(()=>codexSeries.value.filter(item=>localDayKey(new Date(item.at*1000))===localDayKey(new Date(now.value))).length)
const todayCalls=computed(()=>todayCodexTurns.value+usage.value.filter(item=>localDayKey(new Date(item.at))===localDayKey(new Date(now.value))).length)
const floatingTodayTokens=computed(()=>selectedDashboard.value==='__all__'?todayTotalTokens.value:selectedDashboard.value==='__codex__'?codexTodayTokens.value:dashboardInput.value+dashboardOutput.value)
const floatingWeekCost=computed(()=>selectedDashboard.value==='__all__'?weekCost.value:dashboardUsage.value.filter(item=>new Date(item.at).getTime()>=now.value-7*86_400_000).reduce((sum,item)=>sum+item.cost,0))
const floatingTodayCalls=computed(()=>selectedDashboard.value==='__all__'?todayCalls.value:selectedDashboard.value==='__codex__'?todayCodexTurns.value:dashboardToday.value.length)
const codex7dResetText=computed(()=>{const cutoff=now.value/1000-7*86_400;const oldest=codexSeries.value.filter(item=>item.at>=cutoff).sort((a,b)=>a.at-b.at)[0];if(!oldest)return'暂无滚动记录';let seconds=Math.max(0,Math.floor(oldest.at+7*86_400-now.value/1000));const days=Math.floor(seconds/86_400);seconds%=86_400;const hours=Math.floor(seconds/3600);seconds%=3600;const minutes=Math.floor(seconds/60);return`${days}天 ${hours}时 ${minutes}分 ${seconds%60}秒`})
const modelBalanceRows=computed(()=>modelDashboards.value.map(model=>{const balance=accountBalances.value.find(item=>item.account_id===model.accountId&&item.currency==='CNY');const rows=usage.value.filter(item=>item.provider===model.provider&&item.model===model.model);const tokens=rows.reduce((sum,item)=>sum+item.input+item.output,0);return{key:model.key,label:model.label,value:balance?`¥${balance.total_balance.toFixed(2)}`:rows.length?`${tokens.toLocaleString()} tokens`:'暂无调用'}}).slice(0,4))
const enabledFloatingModules=computed(()=>floatingConfig.value.order.filter(id=>floatingConfig.value.enabled.includes(id)).filter(id=>selectedDashboard.value==='__codex__'?!['weekCost','modelBalances'].includes(id):isApiDashboard.value?!['codexQuota','estimatedDuration','taskCapacity'].includes(id):true))
const miniFloatingModules=computed(()=>{const allowed=floatingConfig.value.mini.filter(id=>enabledFloatingModules.value.includes(id));return [...allowed,...enabledFloatingModules.value.filter(id=>!allowed.includes(id))].slice(0,2)})
function floatingModuleValue(id:FloatingModuleId){return id==='globalRemaining'?(isApiDashboard.value?(dashboardBalance.value?`¥${dashboardBalance.value.total_balance.toFixed(2)}`:'—'):`${globalRemaining.value}%`):id==='todayTokens'?floatingTodayTokens.value.toLocaleString():id==='estimatedDuration'?`${codexInsights.value.debugHours.toFixed(1)} 小时`:id==='taskCapacity'?`${codexInsights.value.bugFixes} 次修复`:id==='weekCost'?`¥${floatingWeekCost.value.toFixed(2)}`:id==='codexQuota'?`${remaining5h.value}% / ${remaining7d.value}%`:id==='modelBalances'?`${modelBalanceRows.value.length} 个模型`:id==='warning'?(isDeepSeekDashboard.value?(dashboardBalance.value?.is_available?'正常':'余额不可用'):balanceLevel.value==='normal'?'正常':balanceLevel.value==='warning'?'低于20%':'低于10%'):floatingTodayCalls.value.toLocaleString()}
function floatingModuleTitle(id:FloatingModuleId){return floatingModuleCatalog.find(item=>item.id===id)?.title||id}
function persistFloatingConfig(){const value:FloatingConfig={enabled:[...floatingConfig.value.enabled],order:[...floatingConfig.value.order],mini:[...floatingConfig.value.mini] as [FloatingModuleId,FloatingModuleId],miniMode:floatingConfig.value.miniMode,layout:floatingConfig.value.layout};localStorage.setItem('token-manager-floating-config',JSON.stringify(value));void emit('floating-config',value)}
function toggleFloatingModule(id:FloatingModuleId,event:Event){const checked=(event.target as HTMLInputElement).checked;floatingConfig.value.enabled=checked?[...new Set([...floatingConfig.value.enabled,id])]:floatingConfig.value.enabled.filter(item=>item!==id);persistFloatingConfig()}
function startFloatingModuleDrag(id:FloatingModuleId){draggedFloatingModule.value=id}
function dropFloatingModule(target:FloatingModuleId){const source=draggedFloatingModule.value;if(!source||source===target)return;const order=[...floatingConfig.value.order];order.splice(order.indexOf(source),1);order.splice(order.indexOf(target),0,source);floatingConfig.value.order=order;draggedFloatingModule.value=null;persistFloatingConfig()}
function moveFloatingModule(id:FloatingModuleId,delta:-1|1){const order=[...floatingConfig.value.order];const from=order.indexOf(id);const to=Math.max(0,Math.min(order.length-1,from+delta));if(from===to)return;order.splice(from,1);order.splice(to,0,id);floatingConfig.value.order=order;persistFloatingConfig()}
function updateMiniModule(index:0|1,event:Event){const value=(event.target as HTMLSelectElement).value as FloatingModuleId;const next=[...floatingConfig.value.mini] as [FloatingModuleId,FloatingModuleId];next[index]=value;if(next[0]===next[1])next[index===0?1:0]=floatingIds.find(id=>id!==value)||'todayTokens';floatingConfig.value.mini=next;persistFloatingConfig()}
function setFloatingLayout(layout:'grid'|'list'){floatingConfig.value.layout=layout;persistFloatingConfig()}
async function rememberExpandedFloatingSize(){if(!floatingMode||floatingCollapsed.value)return;try{const window=getCurrentWindow();const [size,scale]=await Promise.all([window.innerSize(),window.scaleFactor()]);expandedFloatingSize={width:Math.max(300,Math.round(size.width/scale)),height:Math.max(220,Math.round(size.height/scale))};localStorage.setItem('token-manager-floating-size',JSON.stringify(expandedFloatingSize))}catch{}}
async function applyFloatingModeSize(){if(!floatingMode)return;try{await getCurrentWindow().setSize(floatingCollapsed.value?new LogicalSize(360,150):new LogicalSize(expandedFloatingSize.width,expandedFloatingSize.height))}catch{}}
async function initializeFloatingWindow(){if(!floatingMode)return;const window=getCurrentWindow();await applyFloatingModeSize();try{unlistenFloatingResize=await window.onResized(async event=>{if(floatingCollapsed.value)return;const scale=await window.scaleFactor();expandedFloatingSize={width:Math.max(300,Math.round(event.payload.width/scale)),height:Math.max(220,Math.round(event.payload.height/scale))};localStorage.setItem('token-manager-floating-size',JSON.stringify(expandedFloatingSize))})}catch{}}
async function startFloatingDrag(event:MouseEvent){if(!floatingMode||event.button!==0||(event.target as HTMLElement).closest('button,select'))return;try{await getCurrentWindow().startDragging()}catch{}}
async function startFloatingResize(event:PointerEvent){if(!floatingMode||event.button!==0)return;event.preventDefault();event.stopPropagation();const target=event.currentTarget as HTMLElement;target.setPointerCapture(event.pointerId);try{const window=getCurrentWindow();const [size,scale]=await Promise.all([window.innerSize(),window.scaleFactor()]);floatingResizeState={pointerId:event.pointerId,startX:event.screenX,startY:event.screenY,width:size.width/scale,height:size.height/scale}}catch{floatingResizeState=null}}
async function moveFloatingResize(event:PointerEvent){const state=floatingResizeState;if(!state||state.pointerId!==event.pointerId)return;event.preventDefault();const width=Math.max(300,state.width+event.screenX-state.startX);const height=Math.max(140,state.height+event.screenY-state.startY);try{await getCurrentWindow().setSize(new LogicalSize(width,height))}catch{}}
function endFloatingResize(event:PointerEvent){if(floatingResizeState?.pointerId!==event.pointerId)return;floatingResizeState=null;const target=event.currentTarget as HTMLElement;if(target.hasPointerCapture(event.pointerId))target.releasePointerCapture(event.pointerId)}
async function resizeFloatingByKeyboard(event:KeyboardEvent){if(!['ArrowLeft','ArrowRight','ArrowUp','ArrowDown'].includes(event.key))return;event.preventDefault();try{const window=getCurrentWindow();const [size,scale]=await Promise.all([window.innerSize(),window.scaleFactor()]);const width=Math.max(300,size.width/scale+(event.key==='ArrowRight'?20:event.key==='ArrowLeft'?-20:0));const height=Math.max(140,size.height/scale+(event.key==='ArrowDown'?20:event.key==='ArrowUp'?-20:0));await window.setSize(new LogicalSize(width,height))}catch{}}
async function toggleMiniMode(event:Event){const collapsed=(event.target as HTMLInputElement).checked;if(collapsed)await rememberExpandedFloatingSize();floatingConfig.value.miniMode=collapsed;floatingCollapsed.value=collapsed;persistFloatingConfig();await applyFloatingModeSize()}
function syncCurrentView(){return floatingMode?syncFloatingData():syncData()}
async function refreshCcSwitch(){try{ccSwitch.value=await invoke<CcSwitchStatus>('cc_switch_status')}catch{ccSwitch.value={installed:false,running:false,local_routing:false,detail:'检测不可用',checked_at:new Date().toISOString()}}}
async function refreshBalanceData(sync=true){try{accountBalances.value=sync?await invoke<AccountBalance[]>('sync_account_balances'):await invoke<AccountBalance[]>('list_account_balances');balanceError.value='';const accountId=selectedDashboardDef.value?.provider==='DeepSeek'?selectedDashboardDef.value.accountId:'';deepseekBalanceHistory.value=accountId?await invoke<BalancePoint[]>('list_balance_history',{accountId,days:30}):[]}catch(error){balanceError.value=String(error);try{accountBalances.value=await invoke<AccountBalance[]>('list_account_balances')}catch{}}}
async function syncFloatingData(){
 if(isSyncing.value)return
 isSyncing.value=true
 try{
  await refreshCcSwitch()
  await refreshBalanceData(true)
  const [windowUsage,series,events]=await Promise.all([
   invoke<{five_hour_used:number;seven_day_used:number;budget:{five_hour_limit:number;seven_day_limit:number}}>('codex_window_usage'),
   invoke<CodexUsagePoint[]>('codex_usage_series'),
   invoke<Usage[]>('list_usage',{days:7})
  ])
  used5h.value=windowUsage.five_hour_used;used7d.value=windowUsage.seven_day_used
  budget5h.value=windowUsage.budget.five_hour_limit;budget7d.value=windowUsage.budget.seven_day_limit
  codexSeries.value=series;usage.value=events;codexTokens.value=series.reduce((sum,item)=>sum+item.tokens,0);codexError.value=''
 }catch(error){codexError.value=String(error);codexTokens.value=null}
 finally{lastRefreshed.value=Date.now();isSyncing.value=false}
}
async function maybeSendBudgetAlert(){
 const remaining=Math.min(remaining5h.value,remaining7d.value);const level=remaining<=10?10:remaining<=20?20:0
 if(!level)return
 const key=`token-manager-budget-alert-${level}-${localDayKey(new Date())}`
 if(localStorage.getItem(key))return
 try{await invoke('send_budget_alert',{level,remaining});localStorage.setItem(key,'1')}catch{}
}
async function syncData(){
 if(isSyncing.value) return
 isSyncing.value=true
 try {
  await refreshCcSwitch()
  await refreshAccounts()
  await refreshBalanceData(true)
  usage.value=await invoke<Usage[]>('list_usage',{days:30})
  // 桌面端读取本机 Codex 状态库；浏览器预览没有 Tauri 后端时保持“未连接”。
  const [snapshot,windowUsage,series]=await Promise.all([
   invoke<{total_tokens:number;active_thread_tokens:number;updated_at_ms:number}>('codex_snapshot'),
   invoke<{five_hour_used:number;seven_day_used:number;budget:{five_hour_limit:number;seven_day_limit:number}}>('codex_window_usage'),
   invoke<CodexUsagePoint[]>('codex_usage_series')
  ])
  codexTokens.value=snapshot.total_tokens
  codexActiveTokens.value=snapshot.active_thread_tokens
  codexUpdatedAt.value=snapshot.updated_at_ms>0&&snapshot.updated_at_ms<1_000_000_000_000?snapshot.updated_at_ms*1000:snapshot.updated_at_ms
  used5h.value=windowUsage.five_hour_used
  used7d.value=windowUsage.seven_day_used
  codexSeries.value=series
  budget5h.value=windowUsage.budget.five_hour_limit
  budget7d.value=windowUsage.budget.seven_day_limit
  codexError.value=''
  await maybeSendBudgetAlert()
 } catch (error) { codexError.value=String(error) }
 finally { lastRefreshed.value=Date.now(); isSyncing.value=false }
}
async function saveBudget(){
 budgetSaved.value=''
 try { await invoke('save_codex_budget',{fiveHourLimit:budget5h.value,sevenDayLimit:budget7d.value}); budgetSaved.value='预算已保存'; await syncData() }
 catch(error){ budgetSaved.value=`保存失败：${String(error)}` }
}
async function startProxy(){
 proxyStatus.value='正在启动…'
 try { const url=await invoke<string>('start_proxy',{upstream:proxyUpstream.value,port:proxyPort.value,accountId:activeAccountId.value||null}); proxyStatus.value=`运行中：${url}` }
 catch(error){ proxyStatus.value=`启动失败：${String(error)}` }
}
async function startAllProxies(){allProxyStatus.value='正在启动全部账户代理…';try{await refreshAccounts();proxyEndpoints.value=await invoke<ProxyEndpoint[]>('start_all_proxies');allProxyStatus.value=`实时监控已开启：${proxyEndpoints.value.length} 个账户`;await syncData()}catch(error){allProxyStatus.value=String(error);if(!savedAccounts.value.length)page.value='accounts'}}
async function openProviderPortal(p:Provider){
 const url=providerPortals[p.name]
 if(!url) return
 await openUrl(url)
}
function openConfig(p:Provider,account?:SavedAccount){configuring.value=p;editingAccountId.value=account?.id||'';configName.value=account?.name||`${p.name} 账户`;configUrl.value=account?.base_url||providerApiBases[p.name]||'';configKey.value='';configStatus.value=''}
async function saveConfig(){if(!configuring.value)return;configStatus.value='正在加密保存…';try{const id=editingAccountId.value||`${configuring.value.id}-${Date.now()}`;await invoke('save_account_config',{id,provider:configuring.value.name,name:configName.value,baseUrl:configUrl.value,apiKey:configKey.value});activeAccountId.value=id;proxyUpstream.value=configUrl.value;configStatus.value='已永久保存并设为代理账户。';await refreshAccounts()}catch(e){configStatus.value=`保存失败：${String(e)}`}}
async function refreshAccounts(){savedAccounts.value=await invoke<SavedAccount[]>('list_account_configs');for(const p of accounts.value){const count=savedAccounts.value.filter(a=>a.provider===p.name).length;p.configured=count>0;p.description=count?`已保存 ${count} 个加密账户`:'尚未配置'}if(!activeAccountId.value&&savedAccounts.value[0]){activeAccountId.value=savedAccounts.value[0].id;proxyUpstream.value=savedAccounts.value[0].base_url}}
async function deleteSavedAccount(id:string){await invoke('delete_account_config',{id});modelDashboards.value=modelDashboards.value.filter(d=>d.accountId!==id);persistDashboards();await refreshAccounts()}
async function clearSavedAccounts(){if(!confirm('确定清空全部已保存 API 密钥吗？此操作不可恢复。'))return;await invoke('clear_account_configs');modelDashboards.value=[];persistDashboards();await refreshAccounts()}
function persistDashboards(){localStorage.setItem('token-manager-model-dashboards-v2',JSON.stringify(modelDashboards.value))}
function selectDashboard(key:string){selectedDashboard.value=key;localStorage.setItem('token-manager-selected-dashboard',key);void emit('dashboard-selection',key);void refreshBalanceData(false)}
function changeFloatingDashboard(event:Event){selectDashboard((event.target as HTMLSelectElement).value)}
async function toggleFloating(){floatingEnabled.value=!floatingEnabled.value;try{await invoke('set_floating_window',{enabled:floatingEnabled.value});localStorage.setItem('token-manager-floating',floatingEnabled.value?'1':'0')}catch(e){floatingEnabled.value=!floatingEnabled.value;alert(String(e))}}
async function closeFloating(){try{await invoke('set_floating_window',{enabled:false});floatingEnabled.value=false;localStorage.setItem('token-manager-floating','0')}catch(e){alert(String(e))}}
async function toggleFloatingCollapsed(){
 const collapsed=!floatingCollapsed.value
 if(collapsed)await rememberExpandedFloatingSize()
 floatingCollapsed.value=collapsed
 floatingConfig.value.miniMode=collapsed
 persistFloatingConfig()
 await applyFloatingModeSize()
}
async function openDashboardPicker(){dashboardModal.value=true;modelsLoading.value=true;await Promise.all(savedAccounts.value.map(async account=>{try{const models=await invoke<string[]>('fetch_account_models',{id:account.id});if(models.length)accountModels.value[account.id]=models}catch{}}));modelsLoading.value=false}
function addDashboard(){const choice=availableModels.value.find(item=>item.key===newDashboardKey.value);if(!choice)return;if(!modelDashboards.value.some(item=>item.key===choice.key))modelDashboards.value.push(choice);persistDashboards();selectDashboard(choice.key);newDashboardKey.value='';dashboardModal.value=false}
function removeDashboard(key:string){modelDashboards.value=modelDashboards.value.filter(x=>x.key!==key);persistDashboards();if(selectedDashboard.value===key)selectDashboard('__all__')}
function addAccount(p:Provider){ p.configured=true;p.description='本地安全存储，等待同步'; alert(`${p.name} 已启用。请在 Tauri 桌面端的账户抽屉中输入密钥。`) }
function exportBill(){ const rows=['时间,平台,模型,输入Token,输出Token,缓存Token,成本(元),任务',...usage.value.map(x=>`${x.at},${x.provider},${x.model},${x.input},${x.output},${x.cached},${x.cost},${x.task}`)]; const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([rows.join('\n')],{type:'text/csv;charset=utf-8'}));a.download='Token Manager-消费账单.csv';a.click();URL.revokeObjectURL(a.href) }
function collectUiState(){const state:Record<string,string>={};for(let index=0;index<localStorage.length;index++){const key=localStorage.key(index);if(key?.startsWith('token-manager-'))state[key]=localStorage.getItem(key)||''}return state}
async function exportBackup(){backupStatus.value='';if(backupPassword.value.length<8){backupStatus.value='迁移密码至少需要 8 个字符';return}const path=await save({defaultPath:`Token-Manager-${new Date().toISOString().slice(0,10)}.tmbak`,filters:[{name:'Token Manager 加密备份',extensions:['tmbak']}]});if(!path)return;try{await invoke('export_encrypted_backup',{path,password:backupPassword.value,uiState:collectUiState()});backupStatus.value='加密备份已导出'}catch(error){backupStatus.value=`导出失败：${String(error)}`}}
async function importBackup(){backupStatus.value='';if(backupPassword.value.length<8){backupStatus.value='请输入导出时使用的迁移密码';return}const path=await open({multiple:false,filters:[{name:'Token Manager 加密备份',extensions:['tmbak']}]});if(typeof path!=='string')return;try{const state=await invoke<Record<string,string>>('import_encrypted_backup',{path,password:backupPassword.value});for(const [key,value] of Object.entries(state))localStorage.setItem(key,value);backupStatus.value='迁移完成，正在重新载入';setTimeout(()=>location.reload(),500)}catch(error){backupStatus.value=`导入失败：${String(error)}`}}
</script>
<template>
 <main v-if="floatingMode" class="floating-shell" :class="{collapsed:floatingCollapsed}">
