  <div v-if="floatingCollapsed" class="mini-core-row"><span v-for="id in miniFloatingModules"><small>{{floatingModuleTitle(id)}}</small><b>{{floatingModuleValue(id)}}</b></span></div>
  <div v-else class="floating-modules" :class="floatingConfig.layout+'-layout'">
   <section v-for="id in enabledFloatingModules" :key="id" class="floating-module" :class="`module-${id}`">
    <template v-if="id==='globalRemaining'"><div class="floating-module-head"><span>{{selectedDashboard==='__codex__'?'Codex 预算剩余':isApiDashboard?'账户余额状态':'全局总剩余额度'}}</span><strong>{{isApiDashboard?(dashboardBalance?'¥'+dashboardBalance.total_balance.toFixed(2):'—'):globalRemaining+'%'}}</strong></div><div v-if="!isApiDashboard" class="track"><span :style="{width:(100-globalRemaining)+'%'}"></span></div><small v-if="isApiDashboard&&dashboardBalance">充值余额 ¥{{dashboardBalance.topped_up_balance.toFixed(2)}} · 赠送 ¥{{dashboardBalance.granted_balance.toFixed(2)}}</small><small>{{isApiDashboard?(dashboardBalance?'官方更新 '+new Date(dashboardBalance.synced_at).toLocaleTimeString('zh-CN'):balanceStatusText):'以可验证的 Codex 个人预算为准'}}</small></template>
    <template v-else-if="id==='todayTokens'"><div class="floating-module-head"><span>{{selectedDashboard==='__all__'?'今日总消耗 Token':selectedDashboard==='__codex__'?'Codex 今日 Token':'当前模型今日 Token'}}</span><strong>{{floatingTodayTokens.toLocaleString()}}</strong></div><div class="mini-bars"><div v-for="bar in floatingBars" class="mini-bar" :title="`${bar.label} · ${bar.tokens.toLocaleString()} tokens`"><i :style="{height:bar.height+'%'}"></i><small>{{bar.label.slice(0,2)}}</small></div></div></template>
    <template v-else-if="id==='estimatedDuration'"><div class="floating-module-head"><span>剩余开发预估</span><strong>{{codexInsights.debugHours.toFixed(1)}} 小时</strong></div><small>完整生成 {{codexInsights.generationHours.toFixed(1)}} 小时 · 局部调试 {{codexInsights.debugHours.toFixed(1)}} 小时</small></template>
    <template v-else-if="id==='taskCapacity'"><div class="floating-module-head"><span>可执行任务数量</span><strong>{{codexInsights.bugFixes}} 次</strong></div><small>脚本 {{codexInsights.scripts}} · 重构 {{codexInsights.refactors}} · Bug {{codexInsights.bugFixes}}</small></template>
    <template v-else-if="id==='weekCost'"><div class="floating-module-head"><span>{{selectedDashboard==='__all__'?'本周总消耗金额':'当前模型本周金额'}}</span><strong>¥{{floatingWeekCost.toFixed(2)}}</strong></div><small>最近 7 天已计价 API 调用</small></template>
    <template v-else-if="id==='codexQuota'"><div class="floating-module-head"><span>Codex 5 小时余额</span><strong>{{remaining5h}}%</strong></div><div class="track"><span :style="{width:used5hPercent+'%'}"></span></div><div class="floating-module-head sub"><span>7 天滚动额度</span><strong>{{remaining7d}}%</strong></div><small>下一笔额度释放倒计时 {{codex7dResetText}}</small></template>
    <template v-else-if="id==='modelBalances'"><div class="floating-module-head"><span>各模型分项余额</span><strong>{{modelBalanceRows.length}}</strong></div><div class="model-balance-list"><span v-if="!modelBalanceRows.length">尚未添加模型仪表盘</span><span v-for="row in modelBalanceRows"><b>{{row.label}}</b><small>{{row.value}} · 官方余额视接口权限</small></span></div></template>
    <template v-else-if="id==='warning'"><div class="balance-alert" :class="isDeepSeekDashboard?(dashboardBalance?.is_available?'normal':'critical'):balanceLevel">{{floatingModelNotice}}</div></template>
    <template v-else><div class="floating-module-head"><span>{{selectedDashboard==='__all__'?'今日调用总次数':selectedDashboard==='__codex__'?'Codex 今日 turn':'当前模型今日调用'}}</span><strong>{{floatingTodayCalls.toLocaleString()}}</strong></div><small v-if="selectedDashboard==='__all__'">API 调用 {{todayCalls-todayCodexTurns}} 次 · Codex turn {{todayCodexTurns}} 次</small><small v-else-if="selectedDashboard==='__codex__'">本地日志 turn 数</small><small v-else>{{selectedDashboardDef?.provider}} · {{selectedDashboardDef?.model}}</small></template>
   </section>
  </div>
  <small class="floating-sync" role="status" aria-live="polite">API代理 {{proxyEndpoints.length?'运行中':'未开启'}} · CC Switch {{ccSwitch.local_routing?'已连接':ccSwitch.running?'运行中':'未连接'}} · {{nextRefreshText}}</small>
  <i v-if="!floatingCollapsed" class="floating-resize-handle" title="拖动调整悬浮窗大小" role="separator" tabindex="0" aria-label="调整悬浮窗大小，可使用方向键" @keydown="resizeFloatingByKeyboard" @pointerdown="startFloatingResize" @pointermove="moveFloatingResize" @pointerup="endFloatingResize" @pointercancel="endFloatingResize"></i>
 </main>
 <main v-else class="shell">
  <aside><div class="brand"><span>◌</span> Token Manager <small>v{{appVersion}}</small></div><p class="tagline">你的本地 AI 用量管家</p>
   <nav aria-label="主导航"><button v-for="item in [['dashboard','仪表盘','⌂'],['accounts','账户与模型','◎'],['reports','报告中心','◫'],['settings','设置','⚙']]" :class="{active:page===item[0]}" :aria-current="page===item[0]?'page':undefined" @click="page=item[0] as any"><i aria-hidden="true">{{item[2]}}</i>{{item[1]}}</button></nav>
   <div class="privacy">⌁ 所有数据仅保存在本机<br>密钥受 Windows 加密保护</div>
  </aside>
  <section class="content">
   <header><div><h1>{{ {dashboard:'用量概览',accounts:'账户与模型',reports:'报告中心',settings:'设置'}[page] }}</h1><p role="status" aria-live="polite">电脑时间 {{currentTimeText}} · 上次刷新 {{refreshedText}} · {{nextRefreshText}}</p></div><div class="header-actions"><button class="monitor-launch" :class="{running:proxyEndpoints.length}" @click="startAllProxies"><span aria-hidden="true">●</span>{{proxyEndpoints.length?`实时监控中 · ${proxyEndpoints.length}`:'一键开启 API 实时监控'}}</button><button class="sync" :class="{loading:isSyncing}" :disabled="isSyncing" @click="syncData"><span class="sync-icon" aria-hidden="true">↻</span>{{isSyncing?'正在同步…':'同步数据'}}</button></div></header>
   <div v-if="allProxyStatus" class="proxy-launch-status" role="status" aria-live="polite"><b>{{allProxyStatus}}</b><span v-if="proxyEndpoints.length">请把各调用端 Base URL 改为下方对应的本机地址。</span><div v-if="proxyEndpoints.length"><code v-for="endpoint in proxyEndpoints">{{endpoint.name}} · {{endpoint.local_url}}</code></div></div>
   <template v-if="page==='dashboard'">
    <section class="dashboard-switcher" aria-label="模型仪表盘切换"><button :class="{active:selectedDashboard==='__all__'}" :aria-pressed="selectedDashboard==='__all__'" @click="selectDashboard('__all__')">全部模型</button><button class="codex-dashboard-tab" :class="{active:selectedDashboard==='__codex__'}" :aria-pressed="selectedDashboard==='__codex__'" @click="selectDashboard('__codex__')">Codex 专属</button><div v-for="item in modelDashboards" class="dashboard-tab" :class="{active:selectedDashboard===item.key}"><button :aria-pressed="selectedDashboard===item.key" @click="selectDashboard(item.key)">{{item.label}}</button><button class="dashboard-remove" :aria-label="`删除 ${item.label} 仪表盘`" @click="removeDashboard(item.key)">×</button></div><button class="add-dashboard" @click="openDashboardPicker">＋ 添加仪表盘</button></section>
    <div v-if="selectedDashboard==='__all__'" class="dashboard-heading"><div><span class="eyebrow">模型仪表盘</span><h2>{{dashboardTitle}}</h2></div><span>{{dashboardUsage.length}} 条真实调用</span></div>
    <section v-if="selectedDashboard==='__all__'" class="all-dashboard"><div class="all-summary"><div><span>今日全平台总 Token</span><strong>{{todayTotalTokens.toLocaleString()}}</strong><p>Codex 本地日志与所有 API 代理调用的统一总览</p></div><dl><div><dt>API 请求</dt><dd>{{dashboardToday.length}}</dd></div><div><dt>活跃模型</dt><dd>{{activeModelCount}}</dd></div><div><dt>今日成本</dt><dd>¥{{dashboardCost.toFixed(2)}}</dd></div><div><dt>已连接账户</dt><dd>{{savedAccounts.length}}</dd></div></dl></div><div class="all-overview-grid"><section><div class="section-title"><h2>模型用量构成</h2><span>按近30天 Token 排序</span></div><div v-if="providerBreakdown.length" class="provider-ranking"><div v-for="row in providerBreakdown" :key="row.provider"><span><b>{{row.provider}}</b><small>{{row.calls}} 次 · ¥{{row.cost.toFixed(2)}}</small></span><i><em :style="{width:row.percent+'%',background:providerColor(row.provider)}"></em></i><strong>{{row.tokens.toLocaleString()}}</strong></div></div><div v-else class="inline-empty">开启 API 实时监控后，这里会显示各平台占比。</div></section><aside class="monitor-aside"><div class="today-models"><span>今日使用模型</span><div v-if="todayUsedProviders.length" class="today-logo-list"><span v-for="item in todayUsedProviders" :key="item.provider" :title="`${item.provider} · ${item.tokens.toLocaleString()} Token · ${item.calls} 次`"><ProviderMark :name="item.provider" /></span></div><p v-else>今天尚未记录 API 调用。</p></div><div class="connection-state"><span>监控状态</span><strong :class="{online:proxyEndpoints.length}">{{proxyEndpoints.length?'API 代理运行中':'API 代理未开启'}}</strong><small>{{proxyEndpoints.length?`${proxyEndpoints.length} 个账户正在接收数据`:'点击右上角一键启动全部账户。'}}</small></div><div class="cc-switch-state" :class="{connected:ccSwitch.local_routing}"><span><i></i>CC Switch</span><b>{{ccSwitch.local_routing?'本地路由已连接':ccSwitch.running?'运行中 · 路由未连接':ccSwitch.installed?'已安装 · 未运行':'未检测到'}}</b><small>{{ccSwitch.detail}}</small></div><button v-if="!proxyEndpoints.length" @click="startAllProxies">立即开启实时监控</button></aside></div></section>
    <section v-if="selectedDashboard==='__all__'" class="card all-token-history">
     <div class="token-chart-header"><div><h2>Token 消耗记录</h2><p>输入与输出 Token 合计；缓存命中属于输入的一部分，不重复计算。</p></div><div class="token-range" aria-label="Token 图表时间范围"><button :class="{active:tokenChartRange===7}" :aria-pressed="tokenChartRange===7" @click="setTokenChartRange(7)">7 天</button><button :class="{active:tokenChartRange===30}" :aria-pressed="tokenChartRange===30" @click="setTokenChartRange(30)">30 天</button></div></div>
     <div class="token-chart-summary"><span><small>周期累计</small><b>{{allTokenChart.total.toLocaleString()}}</b></span><span><small>日均 Token</small><b>{{tokenChartDailyAverage.toLocaleString()}}</b></span><span><small>峰值日期</small><b>{{allTokenChart.peak?.day||'—'}}</b></span><span><small>活跃 AI</small><b>{{allTokenChart.activeProviders}}</b></span></div>
     <div v-if="allTokenChart.total" class="stacked-token-chart" :class="{'is-30-days':tokenChartRange===30}">
      <div v-for="bar in allTokenChart.rows" :key="bar.key" class="token-day" tabindex="0" :aria-label="`${bar.day}，总计 ${bar.total.toLocaleString()} Token`">
       <div class="token-tooltip"><b>{{bar.day}} · {{bar.total.toLocaleString()}} Token</b><span v-for="segment in bar.segments" :key="segment.provider"><i :style="{background:segment.color}"></i>{{segment.provider}}<strong>{{segment.tokens.toLocaleString()}}</strong></span><small v-if="!bar.segments.length">当日没有调用</small></div>
       <div class="token-stack"><i v-for="segment in bar.segments" :key="segment.provider" :style="{height:segment.height+'%',background:segment.color}" :title="`${segment.provider} ${segment.tokens.toLocaleString()} Token`"></i></div>
       <small>{{bar.label||' '}}</small>
      </div>
     </div>
     <div v-else class="token-chart-empty"><b>还没有可绘制的真实 Token 记录</b><span>开启 API 实时监控或使用 Codex 后，数据会自动写入并在这里按天累计。</span><button v-if="!proxyEndpoints.length" @click="startAllProxies">一键开启 API 实时监控</button></div>
     <div v-if="allTokenChart.legend.length" class="token-legend" aria-label="AI 颜色图例"><span v-for="item in allTokenChart.legend" :key="item.provider"><i :style="{background:item.color}"></i><ProviderMark :name="item.provider==='Codex'?'OpenAI':item.provider"/><b>{{item.provider}}</b><small>{{item.tokens.toLocaleString()}}</small></span></div>
    </section>
    <section v-else-if="selectedDashboard==='__codex__'" class="codex-dashboard"><div class="codex-title"><div><span>Codex · 本地深度监控</span><h2>无需 API Key，读取本机可验证日志</h2><p>额度百分比依据用户设置的个人预算计算，不冒充 OpenAI 官方 Plus 服务端余额。</p></div><button class="outline" @click="syncData">刷新 Codex 数据</button></div><div class="codex-kpis"><article class="card"><span>累计 Token</span><strong>{{codexTokens?.toLocaleString()||'—'}}</strong><small>本地状态库 threads.tokens_used</small></article><article class="card"><span>当前活跃会话</span><strong>{{codexActiveTokens?.toLocaleString()||'—'}}</strong><small>最近更新线程 Token</small></article><article class="card"><span>今日消耗</span><strong>{{codexTodayTokens.toLocaleString()}}</strong><small>{{todayCodexTurns}} 个本地 turn</small></article><article class="card"><span>日志更新时间</span><strong class="time-value">{{codexUpdatedAt?new Date(codexUpdatedAt).toLocaleTimeString('zh-CN'):'—'}}</strong><small>{{codexUpdatedAt?new Date(codexUpdatedAt).toLocaleDateString('zh-CN'):codexError||'等待读取'}}</small></article></div><div class="codex-quota-card card"><div><h2>5 小时滚动预算</h2><strong>{{remaining5h}}%</strong><div class="track"><span :style="{width:used5hPercent+'%'}"></span></div><small>已用 {{used5h.toLocaleString()}} / {{budget5h.toLocaleString()}} Token</small></div><div><h2>7 天滚动预算</h2><strong>{{remaining7d}}%</strong><div class="track"><span :style="{width:used7dPercent+'%'}"></span></div><small>已用 {{used7d.toLocaleString()}} / {{budget7d.toLocaleString()}} Token · 下一笔释放 {{codex7dResetText}}</small></div></div></section>
    <section v-else class="provider-overview card"><div class="provider-overview-title"><ProviderMark :name="selectedDashboardDef?.provider||''" /><div><span class="eyebrow">{{selectedDashboardDef?.provider}} · 独立仪表盘</span><h2>{{selectedDashboardDef?.model}}</h2><p>{{dashboardAccount?.name||'已配置账户'}} · 仅显示当前平台和模型，不混入 Codex 或其他模型。</p></div></div><div class="provider-overview-grid"><span><small>今日总 Token</small><b>{{(dashboardInput+dashboardOutput).toLocaleString()}}</b></span><span><small>缓存命中率</small><b>{{dashboardCacheRate}}%</b></span><span><small>今日请求</small><b>{{dashboardToday.length}}</b></span><span><small>最近调用</small><b>{{dashboardLastUsage?new Date(dashboardLastUsage.at).toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit'}):'暂无'}}</b></span></div></section>
    <CodexRetentionPanel v-if="selectedDashboard==='__codex__'" :points="codexSeries" :seven-day-used="used7d" :seven-day-budget="budget7d" :remaining5h="remaining5h" :remaining7d="remaining7d" :reset-text="codex7dResetText" />
    <section v-if="selectedDashboard==='__all__'" class="all-cost-analytics"><div class="card cost-share"><div class="section-title"><div><h2>本月模型花费占比</h2><span>仅统计已有价格来源的调用</span></div><strong>¥{{monthlyCostTotal.toFixed(2)}}</strong></div><div class="cost-share-body"><div class="cost-ring" :style="{background:monthlyCostGradient}"><span>已计价<br><b>{{monthlyProviderCosts.length}}</b> 个平台</span></div><div><div v-for="item in monthlyProviderCosts.slice(0,6)"><ProviderMark :name="item.provider"/><span><b>{{item.provider}}</b><small>¥{{item.cost.toFixed(2)}}</small></span><strong>{{monthlyCostTotal?Math.round(item.cost/monthlyCostTotal*100):0}}%</strong></div><p v-if="!monthlyProviderCosts.length">暂无已计价调用，图表不会填充模拟数据。</p></div></div></div><div class="card cost-trend"><div class="section-title"><div><h2>30 天消费趋势</h2><span>鼠标悬停模型明细可查看具体金额</span></div><small>{{priceCatalog.version}}</small></div><svg viewBox="0 0 600 150" preserveAspectRatio="none" aria-label="30天消费金额折线图"><polyline :points="monthlyCostTrend" fill="none" stroke="#111" stroke-width="3" vector-effect="non-scaling-stroke"/></svg><div><span>30 天前</span><span>今天</span></div></div></section>
    <section v-if="isDeepSeekDashboard" class="deepseek-monitor">
     <div class="deepseek-metrics">
      <article class="card balance-primary"><span>官方可用余额</span><strong>{{dashboardBalance?'¥'+dashboardBalance.total_balance.toFixed(2):'—'}}</strong><small>{{dashboardBalance?.is_available?'账户可正常调用':balanceError||'等待官方余额同步'}}</small></article>
      <article class="card"><span>充值余额</span><strong>{{dashboardBalance?'¥'+dashboardBalance.topped_up_balance.toFixed(2):'—'}}</strong><small>DeepSeek 官方返回</small></article>
      <article class="card"><span>赠送余额</span><strong>{{dashboardBalance?'¥'+dashboardBalance.granted_balance.toFixed(2):'—'}}</strong><small>未过期赠金</small></article>
      <article class="card"><span>本次监控变化</span><strong :class="{negative:balanceChange<0}">{{balanceChange?`${balanceChange>0?'+':''}¥${balanceChange.toFixed(2)}`:'¥0.00'}}</strong><small>最近 30 天本机采样</small></article>
     </div>
     <section class="card balance-chart"><div class="row"><div><span class="eyebrow">DEEPSEEK · 官方余额</span><h2>余额变化曲线</h2></div><small>{{dashboardBalance?'更新于 '+new Date(dashboardBalance.synced_at).toLocaleString('zh-CN'):'每 60 秒自动同步'}}</small></div><div v-if="deepseekBalanceHistory.length" class="balance-plot"><svg viewBox="0 0 600 160" preserveAspectRatio="none" aria-label="DeepSeek 余额变化曲线"><polyline :points="deepseekBalancePoints" fill="none" stroke="#111" stroke-width="4" vector-effect="non-scaling-stroke"/><circle v-for="(point,index) in deepseekBalanceHistory" :cx="deepseekBalanceHistory.length===1?300:index/(deepseekBalanceHistory.length-1)*600" :cy="140-(point.total_balance-Math.min(...deepseekBalanceHistory.map(x=>x.total_balance)))/Math.max(.01,Math.max(...deepseekBalanceHistory.map(x=>x.total_balance))-Math.min(...deepseekBalanceHistory.map(x=>x.total_balance)))*115" r="6"><title>{{new Date(point.at).toLocaleString('zh-CN')}} · ¥{{point.total_balance.toFixed(2)}}</title></circle></svg><div><span>起始 ¥{{deepseekBalanceHistory[0].total_balance.toFixed(2)}}</span><span>当前 ¥{{deepseekBalanceHistory[deepseekBalanceHistory.length-1].total_balance.toFixed(2)}}</span></div></div><div v-else class="balance-chart-empty">首次同步后开始记录真实余额变化，不使用模拟数据。</div></section>
     <p class="deepseek-source">余额来自 DeepSeek 官方 <code>/user/balance</code>；V4 Pro 本地代理按缓存命中、缓存未命中和输出 Token 分项计价。</p>
    </section>
    <section v-if="isApiDashboard&&!dashboardUsage.length&&!dashboardBalance" class="card dashboard-empty" role="status"><span aria-hidden="true">◎</span><div><h2>尚未收到 {{selectedDashboardDef?.model}} 的调用数据</h2><p>该模型的统计面板已经就绪。请点击右上角“一键开启 API 实时监控”，再把调用端 Base URL 改为对应本机地址。</p><div class="empty-actions"><button @click="startAllProxies">开启实时监控</button><button class="outline" :disabled="isSyncing" @click="syncData">{{isSyncing?'正在同步…':'立即同步'}}</button></div></div></section>
    <div v-if="isApiDashboard" class="model-kpis"><article class="card token-primary"><span>今日 Token</span><strong>{{(dashboardInput+dashboardOutput).toLocaleString()}}</strong><small>输入 {{dashboardInput.toLocaleString()}} · 输出 {{dashboardOutput.toLocaleString()}}</small></article><article class="card"><span>API 请求</span><strong>{{dashboardToday.length}}</strong><small>成功 {{dashboardToday.length-dashboardFailedCalls}} · 失败 {{dashboardFailedCalls}}</small></article><article class="card"><span>缓存命中</span><strong>{{dashboardCached.toLocaleString()}}</strong><small>命中率 {{dashboardCacheRate}}%</small></article><article class="card"><span>今日成本</span><strong>¥{{dashboardCost.toFixed(4)}}</strong><small>{{dashboardCost?'按已验证价格':'尚未配置模型价格'}}</small></article><article class="card balance-compact"><span>账户余额</span><strong>{{dashboardBalance?'¥'+dashboardBalance.total_balance.toFixed(2):'—'}}</strong><small v-if="dashboardBalance">充值 ¥{{dashboardBalance.topped_up_balance.toFixed(2)}} · 赠送 ¥{{dashboardBalance.granted_balance.toFixed(2)}}</small><small v-else>{{balanceStatusText}}</small></article></div>
    <div v-if="isApiDashboard" class="model-chart-grid"><section v-for="chart in [{key:'costHeight',title:'消费金额',unit:'元'},{key:'tokenHeight',title:'Token 累计',unit:'Token'},{key:'callsHeight',title:'API 请求',unit:'次'},{key:'cacheHeight',title:'缓存命中',unit:'Token'}]" class="card metric-chart"><div class="row"><h2>{{chart.title}}</h2><small>近 7 天 · 悬停查看</small></div><div class="metric-bars"><div v-for="bar in modelChartSeries" class="metric-bar" tabindex="0"><div class="bar-tooltip"><b>{{bar.day}}</b><span v-if="chart.key==='costHeight'">¥{{bar.cost.toFixed(4)}}</span><span v-else-if="chart.key==='tokenHeight'">{{bar.cumulative.toLocaleString()}} Token</span><span v-else-if="chart.key==='callsHeight'">{{bar.calls}} 次</span><span v-else>{{bar.cached.toLocaleString()}} Token</span></div><i :style="{height:(bar as any)[chart.key]+'%'}"></i><small>{{bar.label}}</small></div></div></section></div>
    <section v-if="isApiDashboard" class="card advice model-advice"><h2>{{selectedDashboardDef?.model}} 数据说明</h2><p>Token、请求次数和缓存命中来自本地代理响应；余额按平台官方接口能力单独标注。</p><p v-for="text in dashboardAdvice">{{text}}</p></section>
    <div v-if="selectedDashboard==='__codex__'" class="grid"><section class="card chart"><div class="row"><h2>Codex · 近 7 天 turn 用量</h2><small class="chart-hint">悬停查看每日具体数据</small></div><div class="usage-bars"><div v-for="bar in chartBars" :key="bar.day" class="usage-bar" tabindex="0"><div class="bar-tooltip"><b>{{bar.day}}</b><span>Codex {{bar.codex.toLocaleString()}}</span><span>总量 {{bar.total.toLocaleString()}}</span></div><i :style="{height:bar.height+'%'}"></i><small>{{bar.label}}</small></div></div></section><section class="card advice"><h2>Codex 数据说明</h2><p v-for="text in dashboardAdvice">{{text}}</p></section></div>
    <section v-if="selectedDashboard==='__codex__'" class="card recent"><div class="row"><h2>最近 Codex turns</h2><small>本地日志，不含会话正文</small></div><table><thead><tr><th>时间</th><th>模型</th><th>Token</th><th>来源</th></tr></thead><tbody><tr v-for="point in [...codexSeries].reverse().slice(0,12)"><td>{{new Date(point.at*1000).toLocaleString('zh-CN')}}</td><td>{{point.model}}</td><td>{{point.tokens.toLocaleString()}}</td><td>Codex 本地日志</td></tr><tr v-if="!codexSeries.length"><td colspan="4" class="table-empty">尚未解析到 Codex turn 记录</td></tr></tbody></table></section><section v-else class="card recent"><div class="row"><h2>最近 API 请求</h2><button class="text" @click="exportBill">导出账单</button></div><table><thead><tr><th>平台 / 模型</th><th>状态</th><th>输入 / 输出 / 缓存</th><th>成本</th></tr></thead><tbody><tr v-for="u in dashboardUsage"><td><b>{{u.provider}}</b><small>{{u.model}}</small></td><td>{{u.task==='失败'?'失败':'成功'}}</td><td>{{u.input.toLocaleString()}} / {{u.output.toLocaleString()}} / {{u.cached.toLocaleString()}}</td><td>{{u.cost?'¥'+u.cost.toFixed(4):'未计价'}}</td></tr><tr v-if="!dashboardUsage.length"><td colspan="4" class="table-empty">尚无真实代理请求记录</td></tr></tbody></table></section>
   </template>
   <template v-else-if="page==='accounts'"><div class="account-intro"><div><h2>接入你的模型账户</h2><p class="intro">密钥永久保存为 Windows DPAPI 密文；应用重启后自动恢复账户和模型选项。</p></div><button v-if="savedAccounts.length" class="danger-outline" @click="clearSavedAccounts">清空全部密钥</button></div><div class="providers"><article class="card provider" v-for="p in accounts"><div class="provider-body"><div><div class="provider-head"><ProviderMark :name="p.name" /><h2>{{p.name}}</h2></div><p>{{p.description}}</p><span class="badge" :class="p.source">{{p.source}}</span></div><div v-if="savedAccounts.some(a=>a.provider===p.name)" class="saved-accounts"><div v-for="account in savedAccounts.filter(a=>a.provider===p.name)"><span><b>{{account.name}}</b><small>{{account.base_url}}</small></span><button class="icon-action" @click="openConfig(p,account)">编辑</button><button class="icon-action danger" @click="deleteSavedAccount(account.id)">删除</button></div></div></div><div class="account-actions"><button class="outline" @click="openProviderPortal(p)">官网 ↗</button><button @click="openConfig(p)">＋ 添加账户</button></div></article></div></template>
   <template v-else-if="page==='reports'"><section class="card report"><span class="eyebrow">本月报告预览</span><h2>累计消费 ¥{{totalCost.toFixed(2)}}</h2><p>报告只汇总已经验证价格的真实代理调用；未配置价格的平台仍会完整统计 Token 和 API 请求次数，并明确标记为“未计价”。</p><button @click="exportBill">导出 CSV 账单（Excel 可打开）</button></section></template>
   <template v-else><section class="card settings"><h2>悬浮窗与后台</h2><p>悬浮窗可拖动、始终置顶，并可从右下角自由调整大小；主窗口关闭后自动最小化到系统托盘。</p><button @click="toggleFloating">{{floatingEnabled?'关闭悬浮窗':'一键启用悬浮窗'}}</button><small class="save-note" role="status" aria-live="polite">{{floatingEnabled?'悬浮窗已开启':'悬浮窗已关闭'}}</small><div class="floating-configurator"><div class="module-settings"><div class="setting-section-title"><div><h3>悬浮窗展示模块</h3><p>勾选即时显示；拖动手柄或聚焦模块后按 Alt＋↑/↓ 调整顺序。</p></div><span>{{floatingConfig.enabled.length}} / {{floatingModuleCatalog.length}} 已启用</span></div><div class="floating-layout-setting"><span>模块排列</span><button :class="{active:floatingConfig.layout==='grid'}" :aria-pressed="floatingConfig.layout==='grid'" @click="setFloatingLayout('grid')">▦ 卡片网格</button><button :class="{active:floatingConfig.layout==='list'}" :aria-pressed="floatingConfig.layout==='list'" @click="setFloatingLayout('list')">☷ 单列列表</button></div><div class="module-checklist"><label v-for="id in floatingConfig.order" :key="id" tabindex="0" draggable="true" :aria-label="`${floatingModuleTitle(id)}，按 Alt 加上箭头或下箭头调整顺序`" @keydown.alt.up.prevent="moveFloatingModule(id,-1)" @keydown.alt.down.prevent="moveFloatingModule(id,1)" @dragstart="startFloatingModuleDrag(id)" @dragover.prevent @drop="dropFloatingModule(id)"><i aria-hidden="true">⋮⋮</i><input type="checkbox" :checked="floatingConfig.enabled.includes(id)" @change="toggleFloatingModule(id,$event)"><span><b>{{floatingModuleTitle(id)}}</b><small>{{floatingModuleCatalog.find(item=>item.id===id)?.description}}</small></span></label></div><div class="mini-settings"><h3>迷你折叠模式</h3><p>启用后仅显示下面两个核心模块，状态与布局都会持久保存。</p><label class="mini-mode-toggle"><input type="checkbox" :checked="floatingConfig.miniMode" @change="toggleMiniMode($event)">立即使用迷你模式</label><label>核心模块一<select :value="floatingConfig.mini[0]" @change="updateMiniModule(0,$event)"><option v-for="item in floatingModuleCatalog" :value="item.id">{{item.title}}</option></select></label><label>核心模块二<select :value="floatingConfig.mini[1]" @change="updateMiniModule(1,$event)"><option v-for="item in floatingModuleCatalog" :value="item.id">{{item.title}}</option></select></label></div></div><aside class="floating-preview"><span>实时预览</span><div class="preview-window" :class="floatingConfig.layout"><header><b>Token Manager</b><small>v{{appVersion}}</small></header><div v-for="id in enabledFloatingModules" class="preview-module"><span>{{floatingModuleTitle(id)}}</span><b>{{floatingModuleValue(id)}}</b></div><small v-if="!enabledFloatingModules.length">请至少勾选一个展示模块</small></div><p>配置已自动保存在本机，并实时同步到悬浮窗。</p></aside></div><hr><h2>Codex 个人预算</h2><p>设置 5 小时和 7 天的个人 token 上限，仪表盘会据此显示剩余百分比。</p><div class="budget-fields"><label>5 小时上限 <input v-model.number="budget5h" type="number" min="1" step="1000"> tokens</label><label>7 天上限 <input v-model.number="budget7d" type="number" min="1" step="1000"> tokens</label></div><button @click="saveBudget">保存预算</button><small v-if="budgetSaved" class="save-note" role="status">{{budgetSaved}}</small><hr><h2>单账户代理调试</h2><p>高级用户可在这里手动启动指定上游和端口；普通用户直接使用页面右上角的“一键开启 API 实时监控”。</p><div class="proxy-fields"><label>上游 API 地址<input v-model.trim="proxyUpstream"></label><label>监听端口<input v-model.number="proxyPort" type="number" min="1024" max="65535"></label></div><button @click="startProxy">启动单账户代理</button><small class="save-note" role="status" aria-live="polite">{{proxyStatus}}</small></section></template>
   <section v-if="page==='settings'" class="beginner-guide"><div class="guide-heading"><div><h2>新手配置教程</h2><p>照着下面四步操作，不需要理解代理原理。</p></div><span>{{savedAccounts.length?'账户已准备':'从第一步开始'}}</span></div><ol><li><b>添加 API 账户</b><p>进入“账户与模型”，选择平台，点击“添加账户”，粘贴官网创建的 API Key。密钥只会以 Windows DPAPI 密文保存在本机。</p><button class="outline" @click="page='accounts'">前往添加账户</button></li><li><b>一键开启实时监控</b><p>点击页面右上角的黑色按钮。软件会为每个账户分配一个本机地址，并开始统计 Token、请求次数和错误。</p><button @click="startAllProxies">一键开启</button></li><li><b>修改调用工具的 Base URL</b><p>在你的 SDK、编辑器或第三方工具里，把原厂 Base URL 改成本机代理地址；API Key 可以继续由 Token Manager 加密托管。</p><code>{{proxyEndpoints[0]?.local_url||'http://127.0.0.1:18765/v1'}}</code><small>如果添加了多个账户，每个账户会得到不同端口，启动后会显示完整清单。</small></li><li><b>选择仪表盘</b><p>返回仪表盘，打开“全部模型”查看总览，打开“Codex 专属”查看本地额度，或添加单个 API 模型仪表盘查看详细调用。</p><button class="outline" @click="page='dashboard';selectDashboard('__all__')">查看全部模型</button></li></ol><div class="codex-guide-note"><b>Codex 不需要代理</b><span>Codex 专属仪表盘会直接读取本机日志；只需设置个人 5 小时和 7 天预算。</span></div></section>
   <section v-if="page==='settings'" class="card backup-settings"><div><h2>本地加密迁移</h2><p>导出账户密钥、仪表盘布局、项目标签、重置券与历史用量。备份使用迁移密码加密，导入后密钥会重新使用新电脑的 Windows DPAPI 保存。</p></div><label>迁移密码<input v-model="backupPassword" type="password" minlength="8" placeholder="至少 8 个字符"></label><div class="backup-actions"><button @click="exportBackup">导出全部配置</button><button class="outline" @click="importBackup">导入迁移包</button></div><small role="status" aria-live="polite">{{backupStatus||'迁移包完全离线处理，请妥善保管密码。'}}</small></section>
  </section>
  <div v-if="dashboardModal" class="modal-backdrop" @click.self="dashboardModal=false"><section class="config-modal compact"><button class="close" @click="dashboardModal=false">×</button><span class="eyebrow">添加模型仪表盘</span><h2>选择账户中的模型</h2><p v-if="modelsLoading">正在从已配置账户读取模型列表…</p><p v-else-if="availableModels.length">已优先读取账户实际模型；不支持模型发现的平台显示内置目录。</p><p v-else>请先在“账户与模型”中添加一个 API 账户。</p><select v-model="newDashboardKey" :disabled="modelsLoading||!availableModels.length"><option value="">选择账户与模型</option><option v-for="item in availableModels" :value="item.key">{{item.label}}</option></select><button :disabled="!newDashboardKey" @click="addDashboard">添加仪表盘</button></section></div>
  <div v-if="configuring" class="modal-backdrop" @click.self="configuring=null"><section class="config-modal"><button class="close" @click="configuring=null">×</button><div class="provider-head"><ProviderMark :name="configuring.name" /><div><span class="eyebrow">安全配置</span><h2>{{configuring.name}}</h2></div></div><p>API Key 将使用当前 Windows 用户的 DPAPI 加密保存。</p><label>账户名称<input v-model.trim="configName"></label><label>Base URL<input v-model.trim="configUrl" placeholder="https://api.example.com"></label><label>API Key<input v-model="configKey" type="password" :placeholder="editingAccountId?'留空则继续使用已加密保存的密钥':'粘贴官网创建的密钥'"></label><button @click="saveConfig">加密保存账户</button><small>{{configStatus}}</small></section></div>
 </main>
</template>

